async function generateInvoiceC(req, res, next) {
  try {
    // Obtener datos del cuerpo de la solicitud
    const invoiceParams = req.body || {};

    // Validar los datos de entrada
    if (invoiceParams.ImpNeto && isNaN(parseFloat(invoiceParams.ImpNeto))) {
      return res.status(400).json({
        success: false,
        message: 'El importe neto debe ser un número válido'
      });
    }

    if (invoiceParams.DocNro && isNaN(parseInt(invoiceParams.DocNro))) {
      return res.status(400).json({
        success: false,
        message: 'El número de documento debe ser un número válido'
      });
    }

    // Generar la factura con los datos proporcionados
    const invoiceData = await invoiceService.generateInvoiceC(invoiceParams);
    const qrData = await invoiceService.generateQRForInvoice(invoiceData, 'C');
    const pdfData = await invoiceService.createPDFForInvoice(invoiceData, qrData, 'C');

    // Guardar la factura en la base de datos
    const saveResult = await dbService.saveInvoice(invoiceData, qrData, pdfData, 'C');

    res.status(200).json({
      success: true,
      data: {
        invoice: invoiceData,
        qr: qrData,
        pdf: pdfData,
        dbSave: saveResult
      }
    });
  } catch (error) {
    console.error('Error en el controlador de Factura C:', error.message);
    next(error);
  }
}

@user 
async function generateInvoiceC(invoiceData = {}) {
  try {
    // Obtener el punto de venta desde los datos o usar el predeterminado
    const ptoVta = invoiceData.PtoVta || puntoDeVenta;

    const lastVoucher = await afip.ElectronicBilling.getLastVoucher(ptoVta, tipoDeFacturaC);
    const nextVoucher = invoiceData.CbteDesde || (lastVoucher + 1);

    console.log(`Creando Factura C número: ${nextVoucher}`);

    const today = new Date();
    const formattedDate = formatDate(today);

    // Para Factura C, el ImpIVA es siempre 0 y el ImpTotal es igual al ImpNeto
    const impNeto = invoiceData.ImpNeto || 100;
    const impTotal = invoiceData.ImpTotal || impNeto;

    const data = {
      CantReg: 1,
      PtoVta: ptoVta,
      CbteTipo: tipoDeFacturaC,
      Concepto: 1,
      DocTipo: invoiceData.DocTipo || 99,
      DocNro: invoiceData.DocNro || 0,
      CbteDesde: nextVoucher,
      CbteHasta: nextVoucher,
      CbteFch: parseInt(formattedDate.replace(/-/g, '')),
      FchServDesde: null,
      FchServHasta: null,
      FchVtoPago: null,
      ImpTotal: impTotal,
      ImpTotConc: 0,
      ImpNeto: impNeto,
      ImpOpEx: 0,
      ImpIVA: 0,
      ImpTrib: 0,
      MonId: 'PES',
      MonCotiz: 1
    };

    const response = await afip.ElectronicBilling.createVoucher(data);

    console.log('Datos de Factura C:', data);
    console.log(`CAE asignado: ${response.CAE}`);
    console.log(`Fecha de vencimiento del CAE: ${response.CAEFchVto.substring(0, 4)}-${response.CAEFchVto.substring(4, 6)}-${response.CAEFchVto.substring(6, 8)}`);

    return {
      ...data,
      CAE: response.CAE,
      CAEFchVto: response.CAEFchVto,
      formattedDate
    };
  } catch (error) {
    console.error('Error al generar Factura C:', error.message);
    throw error;
  }
}
